class Library:
    def __init__(self, name, location, books_count, secret_code):
        self.name = name
        self.location = location
        self.__books_count = books_count  # Private attribute
        self.__secret_code = secret_code  # Private attribute

    def get_books_count(self):
        return self.__books_count  # Return the number of books

    def set_books_count(self, books_count, provided_secret_code):
        if provided_secret_code == self.__secret_code:
            self.__books_count = books_count  # Update the book count
        else:
            print("Invalid secret code")

    def show_library_info(self):
        print(f"Library Name: {self.name}")
        print(f"Library Location: {self.location}")

def default_test():
    library = Library("City Library", "Downtown", 10000, "Secret123")
    library.show_library_info()
    print("Current Books Count:", library.get_books_count())
    library.set_books_count(12000, "WrongCode")  # Output: Invalid secret code
    library.set_books_count(12000, "Secret123")  # Updates the books count
    print("Updated Books Count:", library.get_books_count())
